// Adiciona task primeiro
cy.get('[data-cy="task-input"]').type('Task to delete{enter}');
// Conta tasks antes
cy.get('[data-cy="task-item"]').then($items => {
  const countBefore = $items.length;
  // Deleta primeira
  cy.get('[data-cy="task-item"]').first().within(() => {
    cy.get('[data-cy="delete-button"]').click();
  });
  // Verifica que tem 1 a menos
  cy.get('[data-cy="task-item"]').should('have.length', countBefore - 1);
});

// Adiciona 2 tasks
cy.get('[data-cy="task-input"]').type('Task 1{enter}');
cy.get('[data-cy="task-input"]').type('Task 2{enter}');
// Marca ambas como completas
cy.get('[data-cy="task-item"]').eq(0).within(() => {
  cy.get('[data-cy="task-checkbox"]').check();
});
cy.get('[data-cy="task-item"]').eq(1).within(() => {
  cy.get('[data-cy="task-checkbox"]').check();
});
// Clica "Clear completed"
cy.get('[data-cy="clear-completed"]').click();
// Verifica que todas completas foram removidas
cy.get('[data-cy="task-item"]').should('not.exist');

const newTask = 'Task via Enter key';
cy.get('[data-cy="task-input"]').type(`${newTask}{enter}`);
cy.get('[data-cy="task-item"]').first().within(() => {
  cy.get('[data-cy="task-title"]').should('contain', newTask);
});

// Limpa tudo primeiro
cy.get('[data-cy="task-item"]').then($items => {
  if ($items.length > 0) {
    // Marca todas como completas
    cy.get('[data-cy="task-checkbox"]').check({
      multiple: true
    });
    // Limpa completas
    cy.get('[data-cy="clear-completed"]').click();
  }
});
